    command: "uvicorn app.main:app --host 0.0.0.0 --port 5000",
    waitForPort: 5000,
    outputType: "webview"
});

const status = await getWorkflowStatus({ name: "Start application" });
console.log(`State: ${status.state}`);
console.log(`Output:\n${status.output}`);
console.log(`Ports: ${JSON.stringify(status.openPorts)}`);

// Reconfigure backend to port 8000 (console)
await configureWorkflow({
    name: "Backend API",
    command: "uvicorn app.main:app --host 127.0.0.1 --port 8000",
    waitForPort: 8000,
    outputType: "console"
});
console.log("Backend workflow configured on port 8000");

