import { useState, useMemo } from 'react'
import { ArrowUpDown, ArrowUp, ArrowDown, Search } from 'lucide-react'
import { fmtNum } from '@/lib/utils'

interface Row {
  name: string
  value: number | null
  type: 'province' | 'district' | 'national'
}

interface Props {
  rows: Row[]
  unit: string
  indicator: string
}

type SortDir = 'asc' | 'desc' | null

export default function DataTable({ rows, unit, indicator }: Props) {
  const [search, setSearch] = useState('')
  const [sortDir, setSortDir] = useState<SortDir>(null)
  const [page, setPage] = useState(0)
  const PER_PAGE = 10

  const filtered = useMemo(() => {
    const q = search.toLowerCase()
    const base = rows.filter((r) => r.name.toLowerCase().includes(q))
    if (!sortDir) return base
    return [...base].sort((a, b) => {
      const av = a.value ?? -Infinity
      const bv = b.value ?? -Infinity
      return sortDir === 'asc' ? av - bv : bv - av
    })
  }, [rows, search, sortDir])

  const totalPages = Math.ceil(filtered.length / PER_PAGE)
  const paged = filtered.slice(page * PER_PAGE, (page + 1) * PER_PAGE)

  const toggleSort = () =>
    setSortDir((s) => (s === null ? 'desc' : s === 'desc' ? 'asc' : null))

  const isPercent = unit === 'Percentage'

  const SortIcon = () => {
    if (!sortDir) return <ArrowUpDown className="h-3.5 w-3.5 opacity-40" />
    if (sortDir === 'asc') return <ArrowUp className="h-3.5 w-3.5 text-rwanda-green" />
    return <ArrowDown className="h-3.5 w-3.5 text-rwanda-green" />
  }

  return (
    <div className="flex flex-col gap-3">
      {/* Search */}
      <div className="relative w-64">
        <Search className="absolute left-3 top-1/2 h-3.5 w-3.5 -translate-y-1/2 text-slate-400" />
        <input
          value={search}
          onChange={(e) => { setSearch(e.target.value); setPage(0) }}
          placeholder="Search region…"
          className="w-full rounded-lg border border-slate-200 bg-white py-2 pl-8 pr-3 text-sm text-slate-700 placeholder-slate-400 focus:outline-none focus:ring-2 focus:ring-rwanda-green/30"
        />
      </div>

      {/* Table */}
      <div className="overflow-x-auto rounded-xl border border-slate-200 bg-white shadow-sm">
        <table className="w-full text-sm">
          <thead>
            <tr className="border-b border-slate-100 bg-slate-50/60">
              <th className="px-4 py-3 text-left font-semibold text-slate-600">Region</th>
              <th className="px-4 py-3 text-left font-semibold text-slate-600">Type</th>
              <th className="px-4 py-3 text-right">
                <button
                  onClick={toggleSort}
                  className="inline-flex items-center gap-1.5 font-semibold text-slate-600 hover:text-slate-900"
                >
                  {indicator}
                  <SortIcon />
                </button>
              </th>
            </tr>
          </thead>
          <tbody>
            {paged.length === 0 ? (
              <tr>
                <td colSpan={3} className="py-8 text-center text-sm text-slate-400">
                  No data available
                </td>
              </tr>
            ) : (
              paged.map((row, i) => (
                <tr
                  key={i}
                  className="border-b border-slate-50 hover:bg-slate-50/50 transition-colors"
                >
                  <td className="px-4 py-2.5 font-medium text-slate-800">{row.name}</td>
                  <td className="px-4 py-2.5">
                    <span className={`inline-flex rounded-full px-2 py-0.5 text-[11px] font-medium ${
                      row.type === 'national'
                        ? 'bg-red-50 text-red-700'
                        : row.type === 'province'
                        ? 'bg-blue-50 text-blue-700'
                        : 'bg-slate-100 text-slate-600'
                    }`}>
                      {row.type}
                    </span>
                  </td>
                  <td className="px-4 py-2.5 text-right font-semibold text-slate-800">
                    {row.value != null
                      ? `${fmtNum(row.value)}${isPercent ? '%' : ''}`
                      : <span className="text-slate-400">N/A</span>
                    }
                  </td>
                </tr>
              ))
            )}
          </tbody>
        </table>
      </div>

      {/* Pagination */}
      {totalPages > 1 && (
        <div className="flex items-center justify-between text-sm text-slate-500">
          <span>{filtered.length} results</span>
          <div className="flex items-center gap-1">
            <button
              onClick={() => setPage((p) => Math.max(0, p - 1))}
              disabled={page === 0}
              className="rounded-lg border border-slate-200 px-3 py-1 hover:bg-slate-50 disabled:opacity-40"
            >
              ‹
            </button>
            <span className="px-2">{page + 1} / {totalPages}</span>
            <button
              onClick={() => setPage((p) => Math.min(totalPages - 1, p + 1))}
              disabled={page === totalPages - 1}
              className="rounded-lg border border-slate-200 px-3 py-1 hover:bg-slate-50 disabled:opacity-40"
            >
              ›
            </button>
          </div>
        </div>
      )}
    </div>
  )
}

'use client'

import { useState, useMemo, useCallback } from 'react'
import { useQueries } from '@tanstack/react-query'
import { motion, AnimatePresence } from 'framer-motion'
import { AlertCircle, ChevronDown } from 'lucide-react'
import { fetchIndicator } from '@/lib/api'
import { PROVINCES } from '@/lib/types'
import type { ChapterConfig, IndicatorConfig, IndicatorResponse } from '@/lib/types'
import { downloadCSV, fmtNum } from '@/lib/utils'
import ProvinceBarChart from './charts/ProvinceBarChart'
import DataTable from './DataTable'
import Header from './layout/Header'

interface Props {
  chapter: ChapterConfig
}

function Select({
  label, value, onChange, options,
}: {
  label: string
  value: string
  onChange: (v: string) => void
  options: { value: string; label: string }[]
}) {
  return (
    <div className="flex flex-col gap-1">
      <label className="text-[11px] font-semibold uppercase tracking-wide text-slate-500">{label}</label>
      <div className="relative">
        <select
          value={value}
          onChange={(e) => onChange(e.target.value)}
          className="w-full appearance-none rounded-lg border border-slate-200 bg-white py-2 pl-3 pr-8 text-sm font-medium text-slate-800 shadow-sm focus:outline-none focus:ring-2 focus:ring-rwanda-green/30 cursor-pointer"
        >
          {options.map((o) => (
            <option key={o.value} value={o.value}>{o.label}</option>
          ))}
        </select>
        <ChevronDown className="pointer-events-none absolute right-2.5 top-1/2 h-3.5 w-3.5 -translate-y-1/2 text-slate-400" />
      </div>
    </div>
  )
}

export default function ChapterPageClient({ chapter }: Props) {
  const [selectedIndicatorId, setSelectedIndicatorId] = useState(chapter.indicators[0]?.id ?? '')
  const [dynamicParams, setDynamicParams] = useState<Record<string, string>>({})
  const [selectedProvince, setSelectedProvince] = useState<number | null>(null)

  const indicator: IndicatorConfig | undefined = useMemo(
    () => chapter.indicators.find((i) => i.id === selectedIndicatorId),
    [chapter, selectedIndicatorId]
  )

  // Build current params
  const currentParams = useMemo(() => {
    if (!indicator) return {}
    const params: Record<string, string> = { ...indicator.fixedParams }
    indicator.dynamicParams?.forEach((p) => {
      params[p.key] = dynamicParams[p.key] ?? p.default
    })
    return params
  }, [indicator, dynamicParams])

  // Reset dynamic params when indicator changes
  const handleIndicatorChange = useCallback((id: string) => {
    setSelectedIndicatorId(id)
    setDynamicParams({})
    setSelectedProvince(null)
  }, [])

  // Fetch all 5 provinces in parallel
  const queries = useQueries({
    queries: indicator
      ? PROVINCES.map((prov) => ({
          queryKey: ['indicator', indicator.path, { ...currentParams, region: String(prov.code) }],
          queryFn: () => fetchIndicator(indicator.path, { ...currentParams, region: String(prov.code) }),
          enabled: !!indicator,
        }))
      : [],
  })

  const isLoading = queries.some((q) => q.isLoading)
  const isError = queries.some((q) => q.isError)
  const firstSuccess = queries.find((q) => q.data)?.data

  // Province comparison data
  const provinceData = useMemo(() =>
    queries.map((q, i) => ({
      name: PROVINCES[i].name,
      code: PROVINCES[i].code,
      value: q.data?.provinces?.[0]?.value ?? null,
      districts: q.data?.districts ?? [],
    })),
    [queries]
  )

  // District data for selected province
  const districtData = useMemo(() => {
    if (!selectedProvince) return []
    const prov = queries.find((_, i) => PROVINCES[i].code === selectedProvince)
    return prov?.data?.districts ?? []
  }, [queries, selectedProvince])

  // Table rows
  const tableRows = useMemo(() => {
    const national = firstSuccess?.national.value
    const rows = provinceData.map((p) => ({
      name: p.name,
      value: p.value,
      type: 'province' as const,
    }))

    if (selectedProvince) {
      const provName = PROVINCES.find((p) => p.code === selectedProvince)?.name ?? ''
      const distRows = districtData.map((d) => ({
        name: `${d.district_name} (${provName})`,
        value: d.value,
        type: 'district' as const,
      }))
      rows.push(...distRows)
    }

    if (national != null) {
      rows.unshift({ name: 'National', value: national, type: 'national' as const })
    }
    return rows
  }, [provinceData, districtData, firstSuccess, selectedProvince])

  const handleDownloadCSV = useCallback(() => {
    if (!firstSuccess) return
    downloadCSV(
      tableRows.map((r) => ({ name: r.name, value: r.value })),
      firstSuccess.indicator,
      firstSuccess.national.value,
      firstSuccess.unit,
      firstSuccess.data_source
    )
  }, [tableRows, firstSuccess])

  if (!indicator) {
    return <div className="p-8 text-slate-500">No indicators available for this chapter.</div>
  }

  const unit = firstSuccess?.unit ?? 'Percentage'
  const national = firstSuccess?.national.value ?? null

  return (
    <>
      <Header
        title={chapter.title}
        subtitle={firstSuccess ? `${firstSuccess.population_type} · ${firstSuccess.data_source}` : 'DHS Rwanda 2019–20'}
        onDownloadCSV={firstSuccess ? handleDownloadCSV : undefined}
      />

      {/* Print header (hidden on screen) */}
      <div className="print-only p-6 border-b mb-4">
        <h1 className="text-2xl font-bold text-slate-900">{chapter.title}</h1>
        <p className="text-slate-600">{firstSuccess?.indicator} · {firstSuccess?.data_source}</p>
        <p className="text-slate-500 text-sm">Report generated: {new Date().toLocaleDateString('en-GB', { day: 'numeric', month: 'long', year: 'numeric' })}</p>
      </div>

      <div className="p-6 space-y-6">
        {/* Filters */}
        <div className="no-print flex flex-wrap items-end gap-4 rounded-xl border border-slate-200 bg-white p-4 shadow-sm">
          <Select
            label="Indicator"
            value={selectedIndicatorId}
            onChange={handleIndicatorChange}
            options={chapter.indicators.map((i) => ({ value: i.id, label: i.name }))}
          />
          {indicator.dynamicParams?.map((param) => (
            <Select
              key={param.key}
              label={param.label}
              value={dynamicParams[param.key] ?? param.default}
              onChange={(v) => setDynamicParams((prev) => ({ ...prev, [param.key]: v }))}
              options={param.options}
            />
          ))}
        </div>

        {/* Error */}
        {isError && (
          <div className="flex items-center gap-3 rounded-xl border border-red-200 bg-red-50 p-4 text-sm text-red-700">
            <AlertCircle className="h-4 w-4 shrink-0" />
            Failed to load data. Please try again.
          </div>
        )}

        {/* Chart + description */}
        <AnimatePresence mode="wait">
          <motion.div
            key={`${selectedIndicatorId}-${JSON.stringify(currentParams)}`}
            initial={{ opacity: 0, y: 8 }}
            animate={{ opacity: 1, y: 0 }}
            exit={{ opacity: 0 }}
            transition={{ duration: 0.25 }}
            className="rounded-xl border border-slate-200 bg-white p-6 shadow-sm"
          >
            <div className="mb-4 flex flex-col gap-1">
              <div className="flex items-start justify-between gap-4">
                <h2 className="text-base font-semibold text-slate-900">
                  {firstSuccess?.indicator ?? indicator.name}
                </h2>
                {national != null && (
                  <span className="shrink-0 rounded-full bg-red-50 px-2.5 py-1 text-xs font-semibold text-red-700">
                    National: {fmtNum(national)}{unit === 'Percentage' ? '%' : ` ${unit}`}
                  </span>
                )}
              </div>
              <p className="text-sm text-slate-500">{indicator.description}</p>
            </div>

            {isLoading ? (
              <div className="flex h-56 items-center justify-center">
                <div className="flex gap-1.5">
                  {[0, 1, 2].map((i) => (
                    <span
                      key={i}
                      className="inline-block h-2 w-2 animate-bounce rounded-full bg-rwanda-green"
                      style={{ animationDelay: `${i * 0.15}s` }}
                    />
                  ))}
                </div>
              </div>
            ) : (
              <ProvinceBarChart
                data={provinceData}
                national={national}
                unit={unit}
                indicator={firstSuccess?.indicator ?? indicator.name}
                onSelectProvince={(code, name) =>
                  setSelectedProvince((prev) => (prev === code ? null : code))
                }
                selectedProvince={selectedProvince}
              />
            )}

            {!isLoading && selectedProvince && (
              <p className="mt-2 text-center text-xs text-slate-400">
                Click a province bar again to deselect · District breakdown shows in table below
              </p>
            )}
            {!isLoading && !selectedProvince && (
              <p className="mt-2 text-center text-xs text-slate-400">
                Click a province bar to see district-level breakdown
              </p>
            )}
          </motion.div>
        </AnimatePresence>

        {/* District cards (when province selected) */}
        {!isLoading && selectedProvince && districtData.length > 0 && (
          <motion.div
            initial={{ opacity: 0, y: 8 }}
            animate={{ opacity: 1, y: 0 }}
            className="rounded-xl border border-slate-200 bg-white p-6 shadow-sm"
          >
            <h3 className="mb-4 text-sm font-semibold text-slate-800">
              District breakdown ·{' '}
              <span className="font-normal text-slate-500">
                {PROVINCES.find((p) => p.code === selectedProvince)?.name}
              </span>
            </h3>
            <div className="grid grid-cols-2 gap-3 sm:grid-cols-3 lg:grid-cols-4">
              {districtData.map((d) => (
                <div
                  key={d.district_code}
                  className="rounded-lg border border-slate-100 bg-slate-50 p-3"
                >
                  <p className="text-[11px] text-slate-500">{d.district_name}</p>
                  <p className="text-lg font-bold text-rwanda-green">
                    {d.value != null
                      ? `${fmtNum(d.value)}${unit === 'Percentage' ? '%' : ''}`
                      : '—'}
                  </p>
                </div>
              ))}
            </div>
          </motion.div>
        )}

        {/* Data table */}
        {!isLoading && (
          <div className="rounded-xl border border-slate-200 bg-white p-6 shadow-sm">
            <h3 className="mb-4 text-sm font-semibold text-slate-800">Data Table</h3>
            <DataTable
              rows={tableRows}
              unit={unit}
              indicator={firstSuccess?.indicator ?? indicator.name}
            />
          </div>
        )}
      </div>
    </>
  )
}

'use client'

import { useQueries } from '@tanstack/react-query'
import { motion } from 'framer-motion'
import { fetchIndicator } from '@/lib/api'
import { fmtNum } from '@/lib/utils'
import KPICard from '@/components/cards/KPICard'
import Header from '@/components/layout/Header'
import ProvinceBarChart from '@/components/charts/ProvinceBarChart'
import { PROVINCES } from '@/lib/types'
import { useState } from 'react'

const KPI_QUERIES = [
  { path: '/chapter3/fertility-rate', params: { rate_type: 'observed', region: '1' }, title: 'Total Fertility Rate', description: 'National avg', color: 'blue' as const },
  { path: '/chapter4/contraception-use', params: { method: 'modern', marital_status: 'married', region: '1' }, title: 'Modern Contraceptive Use', description: 'Married women', color: 'green' as const },
  { path: '/chapter5/delivery-assistance', params: { provider: 'skilled', region: '1' }, title: 'Skilled Birth Attendance', description: 'Last 5 years', color: 'teal' as const },
  { path: '/chapter7/stunting', params: { severity: 'any', region: '1' }, title: 'Child Stunting', description: 'Children < 5', color: 'rose' as const },
  { path: '/chapter8/itn-ownership', params: { region: '1' }, title: 'ITN Ownership', description: 'Households', color: 'purple' as const },
  { path: '/chapter9/hiv-testing', params: { gender: 'female', timing: 'ever', region: '1' }, title: 'HIV Testing (Women)', description: 'Ever tested, age 15-49', color: 'amber' as const },
]

const COMPARISON_QUERIES = PROVINCES.map((p) => ({
  path: '/chapter4/contraception-use',
  params: { method: 'modern', marital_status: 'married', region: String(p.code) },
  province: p,
}))

export default function OverviewPage() {
  const [, setSelectedProvince] = useState<number | null>(null)

  const kpiResults = useQueries({
    queries: KPI_QUERIES.map((q) => ({
      queryKey: ['kpi', q.path, q.params],
      queryFn: () => fetchIndicator(q.path, q.params),
    })),
  })

  const compResults = useQueries({
    queries: COMPARISON_QUERIES.map((q) => ({
      queryKey: ['overview-comp', q.path, q.params],
      queryFn: () => fetchIndicator(q.path, q.params),
    })),
  })

  const compData = PROVINCES.map((p, i) => ({
    name: p.name,
    code: p.code,
    value: compResults[i]?.data?.provinces?.[0]?.value ?? null,
    districts: compResults[i]?.data?.districts ?? [],
  }))

  const compNational = compResults[0]?.data?.national.value ?? null
  const compLoading = compResults.some((r) => r.isLoading)

  return (
    <>
      <Header />

      {/* Print header */}
      <div className="print-only p-6 border-b mb-4">
        <h1 className="text-2xl font-bold text-slate-900">DHS Rwanda Analytics Dashboard</h1>
        <p className="text-slate-600">Overview Report · Demographic and Health Survey 2019–20</p>
        <p className="text-slate-500 text-sm">Generated: {new Date().toLocaleDateString('en-GB', { day: 'numeric', month: 'long', year: 'numeric' })}</p>
      </div>

      <div className="p-6 space-y-8">
        {/* Welcome banner */}
        <motion.div
          initial={{ opacity: 0, y: 12 }}
          animate={{ opacity: 1, y: 0 }}
          className="rounded-xl border border-green-200 bg-gradient-to-br from-rwanda-green to-green-700 p-6 text-white shadow-sm"
        >
          <h2 className="text-xl font-bold">Rwanda DHS 2019–20</h2>
          <p className="mt-1 text-green-100/90 text-sm max-w-xl">
            Explore health, fertility, nutrition, and demographic indicators across Rwanda's five provinces and 30 districts. Select a chapter from the sidebar to dive into detailed analytics.
          </p>
          <div className="mt-4 flex flex-wrap gap-3">
            {['10 Chapters', '40 Indicators', '5 Provinces', '30 Districts'].map((tag) => (
              <span key={tag} className="rounded-full bg-white/15 px-3 py-1 text-xs font-medium">
                {tag}
              </span>
            ))}
          </div>
        </motion.div>

        {/* KPI Cards */}
        <section>
          <h3 className="mb-4 text-sm font-semibold uppercase tracking-wider text-slate-500">
            Key National Indicators
          </h3>
          <div className="grid grid-cols-2 gap-4 md:grid-cols-3 lg:grid-cols-3">
            {KPI_QUERIES.map((q, i) => {
              const r = kpiResults[i]
              const value = r.data?.national.value
              const unit = r.data?.unit ?? ''
              const isPercent = unit === 'Percentage'
              const display = value != null
                ? `${fmtNum(value)}${isPercent ? '%' : ''}`
                : null
              return (
                <KPICard
                  key={q.path + JSON.stringify(q.params)}
                  title={q.title}
                  value={display}
                  unit={r.data?.unit ?? ''}
                  description={q.description}
                  color={q.color}
                  index={i}
                  isLoading={r.isLoading}
                />
              )
            })}
          </div>
        </section>

        {/* Province comparison spotlight */}
        <section>
          <div className="rounded-xl border border-slate-200 bg-white p-6 shadow-sm">
            <div className="mb-1 flex items-start justify-between">
              <div>
                <h3 className="text-base font-semibold text-slate-900">Modern Contraceptive Use by Province</h3>
                <p className="text-sm text-slate-500">Married women 15-49 · DHS Rwanda 2019–20</p>
              </div>
              {compNational != null && (
                <span className="shrink-0 rounded-full bg-red-50 px-2.5 py-1 text-xs font-semibold text-red-700">
                  National: {fmtNum(compNational)}%
                </span>
              )}
            </div>
            {compLoading ? (
              <div className="flex h-56 items-center justify-center">
                <div className="flex gap-1.5">
                  {[0, 1, 2].map((i) => (
                    <span key={i} className="inline-block h-2 w-2 animate-bounce rounded-full bg-rwanda-green" style={{ animationDelay: `${i * 0.15}s` }} />
                  ))}
                </div>
              </div>
            ) : (
              <ProvinceBarChart
                data={compData}
                national={compNational}
                unit="Percentage"
                indicator="Modern Contraceptive Use"
                onSelectProvince={(code) => setSelectedProvince(code)}
              />
            )}
          </div>
        </section>

        {/* Chapter index */}
        <section>
          <h3 className="mb-4 text-sm font-semibold uppercase tracking-wider text-slate-500">
            Explore by Chapter
          </h3>
          <div className="grid grid-cols-2 gap-3 sm:grid-cols-3 lg:grid-cols-5">
            {[
              { slug: 'household', label: 'Household', emoji: '🏠' },
              { slug: 'demographics', label: 'Demographics', emoji: '👥' },
              { slug: 'fertility', label: 'Fertility', emoji: '👶' },
              { slug: 'family-planning', label: 'Family Planning', emoji: '💊' },
              { slug: 'maternal-health', label: 'Maternal Health', emoji: '🏥' },
              { slug: 'child-health', label: 'Child Health', emoji: '🛡️' },
              { slug: 'nutrition', label: 'Nutrition', emoji: '🥗' },
              { slug: 'malaria', label: 'Malaria', emoji: '🦟' },
              { slug: 'hiv-aids', label: 'HIV/AIDS', emoji: '🔬' },
              { slug: 'gender', label: 'Gender', emoji: '⚖️' },
            ].map((c, i) => (
              <motion.a
                key={c.slug}
                href={`/chapters/${c.slug}`}
                initial={{ opacity: 0, y: 8 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ delay: i * 0.04 }}
                className="flex flex-col items-center gap-2 rounded-xl border border-slate-200 bg-white p-4 text-center shadow-sm transition-smooth hover:border-rwanda-green/40 hover:shadow-md hover:-translate-y-0.5"
              >
                <span className="text-2xl">{c.emoji}</span>
                <span className="text-xs font-medium text-slate-700">{c.label}</span>
              </motion.a>
            ))}
          </div>
        </section>

        {/* Footer note */}
        <p className="text-center text-xs text-slate-400">
          Data source: Rwanda Demographic and Health Survey 2019–20 (RDHS-2020) · NISR & ICF International
        </p>
      </div>
    </>
  )
}

import { notFound } from 'next/navigation'
import { getChapter } from '@/lib/chapters'
import ChapterPageClient from '@/components/ChapterPageClient'

interface Props {
  params: Promise<{ chapter: string }>
}

export default async function ChapterPage({ params }: Props) {
  const { chapter: slug } = await params
  const chapter = getChapter(slug)
  if (!chapter) notFound()
  return <ChapterPageClient chapter={chapter} />
}

export async function generateStaticParams() {
  const { CHAPTERS } = await import('@/lib/chapters')
  return CHAPTERS.map((c) => ({ chapter: c.slug }))
}

